@Override
	public void start() {
		this.lock.lock();
		try {
			if (this.queueToConsumers.isEmpty()) {
				ReceiverOptions receiverOptions =
						new ReceiverOptions()
								// Since 'AmqpConsumer' implements pause/resume logic,
								// the auto-replenishment for the credit window is disabled.
								.creditWindow(0)
								.autoAccept(this.autoAccept);

				for (String queue : this.queues) {
					for (int i = 0; i < this.consumersPerQueue; i++) {
						try {
							Future<Receiver> openFuture =
									this.connectionFactory.getConnection()
											.openReceiver(queue, receiverOptions)
											.openFuture();
							ClientReceiver receiver =
									(ClientReceiver) ProtonUtils.toSupplier(openFuture, receiverOptions.openTimeout())
											.get()
											.addCredit(this.initialCredits);
							AmqpConsumer consumer = new AmqpConsumer(receiver);
							this.queueToConsumers.add(queue, consumer);
							this.taskExecutor.execute(consumer);
						}
						catch (ClientException ex) {
							throw ProtonUtils.toAmqpException(ex);
						}
					}
				}
			}
		}
		finally {
			this.lock.unlock();
		}
	}

private void doInvokeListener(Delivery delivery, Runnable replenishCreditOperation) throws Exception {
	AmqpAcknowledgment amqpAcknowledgment = null;
	if (!this.autoAccept) {
		amqpAcknowledgment = (status) -> {
			try {
				switch (status) {
					case ACCEPT -> delivery.accept();
					case REJECT -> delivery.reject(null, null);
					case REQUEUE -> delivery.release();
				}
				replenishCreditOperation.run();
			}
			catch (ClientException ex) {
				throw ProtonUtils.toAmqpException(ex);
			}
		};
	}

	if (this.proxy instanceof ProtonDeliveryListener protonDeliveryListener) {
		if (protonDeliveryListener instanceof AcknowledgingProtonDeliveryListener ackProtonDeliveryListener) {
			ackProtonDeliveryListener.onDelivery(delivery, amqpAcknowledgment);
		}
		else {
			protonDeliveryListener.onDelivery(delivery);
		}
	}
	else {
		Message message = ProtonUtils.fromProtonMessage(delivery.message());
		if (amqpAcknowledgment != null) {
			message.getMessageProperties()
					.setAmqpAcknowledgment(amqpAcknowledgment);
		}
		this.proxy.onMessage(message);
	}

	if (this.autoAccept) {
		replenishCreditOperation.run();
	}
}

private Message buildMessage(InvocationResult result) {
	Object value = result.getReturnValue();
	if (value instanceof Message msg) {
		return msg;
	}

	MessageProperties messageProperties = new MessageProperties();
	// For a content-type-based routing logic
	if (this.replyContentType != null) {
		messageProperties.setContentType(this.replyContentType);
	}
	Message message;
	if (value == null) {
		message = new Message(new byte[0], messageProperties);
	}
	else {
		Type returnType = result.getReturnType();
		if (value instanceof org.springframework.messaging.Message<?>) {
			message = this.messagingMessageConverter.toMessage(value, messageProperties, returnType);
		}
		else {
			message = this.messageConverter.toMessage(value, messageProperties, returnType);
		}
	}

	// To override the set one by a message converter
	if (this.replyContentType != null) {
		message.getMessageProperties().setContentType(this.replyContentType);
	}
	return message;
}

public void register(StepListener listener) {
	if (listener instanceof StepExecutionListener stepExecutionListener) {
		this.stepListener.register(stepExecutionListener);
	}
	if (listener instanceof ChunkListener cl) {
		this.chunkListener.register(cl);
	}
	if (listener instanceof ItemReadListener<?>) {
		@SuppressWarnings("unchecked")
		ItemReadListener<T> itemReadListener = (ItemReadListener<T>) listener;
		this.itemReadListener.register(itemReadListener);
	}
	if (listener instanceof ItemProcessListener<?, ?>) {
		@SuppressWarnings("unchecked")
		ItemProcessListener<T, S> itemProcessListener = (ItemProcessListener<T, S>) listener;
		this.itemProcessListener.register(itemProcessListener);
	}
	if (listener instanceof ItemWriteListener<?>) {
		@SuppressWarnings("unchecked")
		ItemWriteListener<S> itemWriteListener = (ItemWriteListener<S>) listener;
		this.itemWriteListener.register(itemWriteListener);
	}
	if (listener instanceof SkipListener<?, ?>) {
		@SuppressWarnings("unchecked")
		SkipListener<T, S> skipListener = (SkipListener<T, S>) listener;
		this.skipListener.register(skipListener);
	}
}

@Nullable
		@Override
		protected Object resolveValue(@Nullable Object value) {

			BeanDefinition definition = null;
			String beanName = null;
			if (value instanceof BeanDefinition beanDefinition) {
				definition = beanDefinition;
				beanName = BeanDefinitionReaderUtils.generateBeanName(definition, registry);
			}
			else if (value instanceof BeanDefinitionHolder holder) {
				definition = holder.getBeanDefinition();
				beanName = holder.getBeanName();
			}

			if (definition != null && beanName != null) {
				boolean nestedScoped = scope.equals(definition.getScope());
				boolean scopeChangeRequiresProxy = !scoped && nestedScoped;
				if (scopeChangeRequiresProxy) {
					// Exit here so that nested inner bean definitions are not
					// analysed
					return createScopedProxy(beanName, definition, registry, proxyTargetClass);
				}
			}

			// Nested inner bean definitions are recursively analysed here
			value = super.resolveValue(value);
			return value;

		}

@SuppressWarnings("DataFlowIssue")
	@Override
	public PagingQueryProvider getObject() throws Exception {

		DatabaseType type;
		try {
			type = databaseType != null ? DatabaseType.valueOf(databaseType.toUpperCase())
					: DatabaseType.fromMetaData(dataSource);
		}
		catch (MetaDataAccessException e) {
			throw new IllegalArgumentException(
					"Could not inspect meta data for database type.  You have to supply it explicitly.", e);
		}

		AbstractSqlPagingQueryProvider provider = providers.get(type);
		Assert.state(provider != null, "Should not happen: missing PagingQueryProvider for DatabaseType=" + type);

		provider.setFromClause(fromClause);
		provider.setWhereClause(whereClause);
		provider.setSortKeys(sortKeys);
		if (StringUtils.hasText(selectClause)) {
			provider.setSelectClause(selectClause);
		}
		if (StringUtils.hasText(groupClause)) {
			provider.setGroupClause(groupClause);
		}

		provider.init(dataSource);

		return provider;

	}

@Override
	public void open(ExecutionContext executionContext) throws ItemStreamException {
		super.open(executionContext);
		Assert.notNull(resources, "Resources must be set");

		noInput = false;
		if (resources.length == 0) {
			if (strict) {
				throw new IllegalStateException(
						"No resources to read. Set strict=false if this is not an error condition.");
			}
			else {
				logger.warn("No resources to read. Set strict=true if this should be an error condition.");
				noInput = true;
				return;
			}
		}

		Arrays.sort(resources, comparator);

		if (executionContext.containsKey(getExecutionContextKey(RESOURCE_KEY))) {
			currentResource = executionContext.getInt(getExecutionContextKey(RESOURCE_KEY));

			// context could have been saved before reading anything
			if (currentResource == -1) {
				currentResource = 0;
			}

			delegate.setResource(resources[currentResource]);
			delegate.open(executionContext);
		}
		else {
			currentResource = -1;
		}
	}

@Override
	public ExitStatus run(String... args) throws Exception {
		if (args.length == 0) {
			throw new NoHelpCommandArgumentsException();
		}
		String commandName = args[0];
		for (Command command : this.commandRunner) {
			if (command.getName().equals(commandName)) {
				Log.info(this.commandRunner.getName() + command.getName() + " - " + command.getDescription());
				Log.info("");
				if (command.getUsageHelp() != null) {
					Log.info("usage: " + this.commandRunner.getName() + command.getName() + " "
							+ command.getUsageHelp());
					Log.info("");
				}
				if (command.getHelp() != null) {
					Log.info(command.getHelp());
				}
				Collection<HelpExample> examples = command.getExamples();
				if (examples != null) {
					Log.info((examples.size() != 1) ? "examples:" : "example:");
					Log.info("");
					for (HelpExample example : examples) {
						Log.info("    " + example.getDescription() + ":");
						Log.info("        $ " + example.getExample());
						Log.info("");
					}
					Log.info("");
				}
				return ExitStatus.OK;
			}
		}
		throw new NoSuchCommandException(commandName);
	}

List<String> filter(List<String> configurations) {
	long startTime = System.nanoTime();
	@Nullable String[] candidates = StringUtils.toStringArray(configurations);
	boolean skipped = false;
	for (AutoConfigurationImportFilter filter : this.filters) {
		boolean[] match = filter.match(candidates, this.autoConfigurationMetadata);
		for (int i = 0; i < match.length; i++) {
			if (!match[i]) {
				candidates[i] = null;
				skipped = true;
			}
		}
	}
	if (!skipped) {
		return configurations;
	}
	List<String> result = new ArrayList<>(candidates.length);
	for (String candidate : candidates) {
		if (candidate != null) {
			result.add(candidate);
		}
	}
	if (logger.isTraceEnabled()) {
		int numberFiltered = configurations.size() - result.size();
		logger.trace("Filtered " + numberFiltered + " auto configuration class in "
				+ TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime) + " ms");
	}
	return result;
}

@Override
	public ConditionOutcome getMatchOutcome(ConditionContext context, AnnotatedTypeMetadata metadata) {
		ConditionOutcome matchOutcome = ConditionOutcome.match();
		MergedAnnotations annotations = metadata.getAnnotations();
		if (annotations.isPresent(ConditionalOnBean.class)) {
			Spec<ConditionalOnBean> spec = new Spec<>(context, metadata, annotations, ConditionalOnBean.class);
			matchOutcome = evaluateConditionalOnBean(spec, matchOutcome.getConditionMessage());
			if (!matchOutcome.isMatch()) {
				return matchOutcome;
			}
		}
		if (metadata.isAnnotated(ConditionalOnSingleCandidate.class.getName())) {
			Spec<ConditionalOnSingleCandidate> spec = new SingleCandidateSpec(context, metadata,
					metadata.getAnnotations());
			matchOutcome = evaluateConditionalOnSingleCandidate(spec, matchOutcome.getConditionMessage());
			if (!matchOutcome.isMatch()) {
				return matchOutcome;
			}
		}
		if (metadata.isAnnotated(ConditionalOnMissingBean.class.getName())) {
			Spec<ConditionalOnMissingBean> spec = new Spec<>(context, metadata, annotations,
					ConditionalOnMissingBean.class);
			matchOutcome = evaluateConditionalOnMissingBean(spec, matchOutcome.getConditionMessage());
			if (!matchOutcome.isMatch()) {
				return matchOutcome;
			}
		}
		return matchOutcome;
	}

@Override
		public String toString() {
			boolean hasNames = !this.names.isEmpty();
			boolean hasTypes = !this.types.isEmpty();
			boolean hasIgnoredTypes = !this.ignoredTypes.isEmpty();
			StringBuilder string = new StringBuilder();
			string.append("(");
			if (hasNames) {
				string.append("names: ");
				string.append(StringUtils.collectionToCommaDelimitedString(this.names));
				string.append(hasTypes ? " " : "; ");
			}
			if (hasTypes) {
				string.append("types: ");
				string.append(StringUtils.collectionToCommaDelimitedString(this.types));
				string.append(hasIgnoredTypes ? " " : "; ");
			}
			if (hasIgnoredTypes) {
				string.append("ignored: ");
				string.append(StringUtils.collectionToCommaDelimitedString(this.ignoredTypes));
				string.append("; ");
			}
			if (this.strategy != null) {
				string.append("SearchStrategy: ");
				string.append(this.strategy.toString().toLowerCase(Locale.ENGLISH));
			}
			string.append(")");
			return string.toString();
		}

private List<String> createCommand(Type type) {
	return switch (type) {
		case DOCKER -> new ArrayList<>(this.dockerCommands.get(type).command());
		case DOCKER_COMPOSE -> {
			List<String> result = new ArrayList<>(this.dockerCommands.get(type).command());
			DockerComposeFile composeFile = this.dockerComposeOptions.composeFile();
			if (composeFile != null) {
				for (File file : composeFile.getFiles()) {
					result.add("--file");
					result.add(file.getPath());
				}
			}
			result.add("--ansi");
			result.add("never");
			Set<String> activeProfiles = this.dockerComposeOptions.activeProfiles();
			if (!CollectionUtils.isEmpty(activeProfiles)) {
				for (String profile : activeProfiles) {
					result.add("--profile");
					result.add(profile);
				}
			}
			List<String> arguments = this.dockerComposeOptions.arguments();
			if (!CollectionUtils.isEmpty(arguments)) {
				result.addAll(arguments);
			}
			yield result;
		}
	};
}

private @Nullable PropertySource<?> mapPropertiesWithReplacement(PropertiesMigrationReport report, String name,
			List<PropertyMigration> properties) {
		report.add(name, properties);
		List<PropertyMigration> renamed = properties.stream().filter(PropertyMigration::isCompatibleType).toList();
		if (renamed.isEmpty()) {
			return null;
		}
		NameTrackingPropertySource nameTrackingPropertySource = new NameTrackingPropertySource();
		this.environment.getPropertySources().addFirst(nameTrackingPropertySource);
		try {
			String target = "migrate-" + name;
			Map<String, OriginTrackedValue> content = new LinkedHashMap<>();
			for (PropertyMigration candidate : renamed) {
				String newPropertyName = candidate.getNewPropertyName();
				Object value = candidate.getProperty().getValue();
				if (nameTrackingPropertySource.isPlaceholderThatAccessesName(value, newPropertyName)) {
					continue;
				}
				OriginTrackedValue originTrackedValue = OriginTrackedValue.of(value,
						candidate.getProperty().getOrigin());
				content.put(newPropertyName, originTrackedValue);
			}
			return new OriginTrackedMapPropertySource(target, content);
		}
		finally {
			this.environment.getPropertySources().remove(nameTrackingPropertySource.getName());
		}
	}

@SuppressWarnings("unchecked")
	private void flatten(Properties properties, Map<String, Object> input, @Nullable String path) {
		input.forEach((key, value) -> {
			String name = getPropertyName(path, key);
			if (value instanceof Map) {
				// Need a compound key
				flatten(properties, (Map<String, Object>) value, name);
			}
			else if (value instanceof Collection<?> collection) {
				// Need a compound key
				properties.put(name, StringUtils.collectionToCommaDelimitedString(collection));
				int count = 0;
				for (Object item : collection) {
					String itemKey = "[" + (count++) + "]";
					flatten(properties, Collections.singletonMap(itemKey, item), name);
				}
			}
			else if (value instanceof String) {
				properties.put(name, value);
			}
			else if (value instanceof Number || value instanceof Boolean) {
				properties.put(name, value.toString());
			}
			else {
				properties.put(name, (value != null) ? value : "");
			}
		});
	}

Resource[] getResources(String location, ResourceType type) {
	validatePattern(location, type);
	String directoryPath = location.substring(0, location.indexOf("*/"));
	String fileName = location.substring(location.lastIndexOf("/") + 1);
	Resource resource = getResource(directoryPath);
	if (!resource.exists()) {
		return EMPTY_RESOURCES;
	}
	File file = getFile(location, resource);
	if (!file.isDirectory()) {
		return EMPTY_RESOURCES;
	}
	File[] subDirectories = file.listFiles(this::isVisibleDirectory);
	if (subDirectories == null) {
		return EMPTY_RESOURCES;
	}
	Arrays.sort(subDirectories, FILE_PATH_COMPARATOR);
	if (type == ResourceType.DIRECTORY) {
		return Arrays.stream(subDirectories).map(FileSystemResource::new).toArray(Resource[]::new);
	}
	List<Resource> resources = new ArrayList<>();
	FilenameFilter filter = (dir, name) -> name.equals(fileName);
	for (File subDirectory : subDirectories) {
		File[] files = subDirectory.listFiles(filter);
		if (files != null) {
			Arrays.sort(files, FILE_NAME_COMPARATOR);
			Arrays.stream(files).map(FileSystemResource::new).forEach(resources::add);
		}
	}
	return resources.toArray(EMPTY_RESOURCES);
}

@Override
	public <T> @Nullable T bind(ConfigurationPropertyName name, Bindable<T> target, Binder.Context context,
			DataObjectPropertyBinder propertyBinder, boolean fallbackToDefaultValue) {
		ValueObject<T> valueObject = ValueObject.get(target, context, this.constructorProvider, Discoverer.LENIENT);
		if (valueObject != null) {
			Class<?> targetType = target.getType().resolve();
			Assert.state(targetType != null, "'targetType' must not be null");
			context.pushConstructorBoundTypes(targetType);
			List<ConstructorParameter> parameters = valueObject.getConstructorParameters();
			List<@Nullable Object> args = new ArrayList<>(parameters.size());
			boolean bound = false;
			for (ConstructorParameter parameter : parameters) {
				Object arg = parameter.bind(propertyBinder);
				bound = bound || arg != null;
				arg = (arg != null) ? arg : getDefaultValue(context, parameter);
				args.add(arg);
			}
			context.clearConfigurationProperty();
			context.popConstructorBoundTypes();
			if (bound) {
				return valueObject.instantiate(args);
			}
		}
		if (fallbackToDefaultValue) {
			return getNewDefaultValueInstanceIfPossible(context, target.getType());
		}
		return null;
	}

@SuppressWarnings("unchecked")
	private <T> @Nullable T getNewDefaultValueInstanceIfPossible(Binder.Context context, ResolvableType type) {
		Class<T> resolved = (Class<T>) type.resolve();
		Assert.state(resolved == null || isEmptyDefaultValueAllowed(resolved),
				() -> "Parameter of type " + type + " must have a non-empty default value.");
		if (resolved != null) {
			if (Optional.class == resolved) {
				return (T) Optional.empty();
			}
			if (Collection.class.isAssignableFrom(resolved)) {
				return (T) CollectionFactory.createCollection(resolved, 0);
			}
			if (EnumMap.class.isAssignableFrom(resolved)) {
				Class<?> keyType = type.asMap().resolveGeneric(0);
				return (T) CollectionFactory.createMap(resolved, keyType, 0);
			}
			if (Map.class.isAssignableFrom(resolved)) {
				return (T) CollectionFactory.createMap(resolved, 0);
			}
			if (resolved.isArray()) {
				return (T) Array.newInstance(resolved.getComponentType(), 0);
			}
		}
		T instance = create(Bindable.of(type), context);
		if (instance != null) {
			return instance;
		}
		return (resolved != null) ? BeanUtils.instantiateClass(resolved) : null;
	}

Elements parse(@Nullable Function<CharSequence, CharSequence> valueProcessor) {
	int length = this.source.length();
	int openBracketCount = 0;
	int start = 0;
	ElementType type = ElementType.EMPTY;
	for (int i = 0; i < length; i++) {
		char ch = this.source.charAt(i);
		if (ch == '[') {
			if (openBracketCount == 0) {
				add(start, i, type, valueProcessor);
				start = i + 1;
				type = ElementType.NUMERICALLY_INDEXED;
			}
			openBracketCount++;
		}
		else if (ch == ']') {
			openBracketCount--;
			if (openBracketCount == 0) {
				add(start, i, type, valueProcessor);
				start = i + 1;
				type = ElementType.EMPTY;
			}
		}
		else if (!type.isIndexed() && ch == this.separator) {
			add(start, i, type, valueProcessor);
			start = i + 1;
			type = ElementType.EMPTY;
		}
		else {
			type = updateType(type, ch, i - start);
		}
	}
	if (openBracketCount != 0) {
		type = ElementType.NON_UNIFORM;
	}
	add(start, length, type, valueProcessor);
	return new Elements(this.source, this.size, this.start, this.end, this.type, null, this.resolved);
}

List<Document> load(@Nullable Charset encoding, boolean expandLists) throws IOException {
	List<Document> documents = new ArrayList<>();
	Document document = new Document();
	StringBuilder buffer = new StringBuilder();
	try (CharacterReader reader = new CharacterReader(this.resource, encoding)) {
		while (reader.read()) {
			if (reader.isCommentPrefixCharacter()) {
				char commentPrefixCharacter = reader.getCharacter();
				if (isNewDocument(reader)) {
					if (!document.isEmpty()) {
						documents.add(document);
					}
					document = new Document();
				}
				else {
					if (document.isEmpty() && !documents.isEmpty()) {
						document = documents.remove(documents.size() - 1);
					}
					reader.setLastLineCommentPrefixCharacter(commentPrefixCharacter);
					reader.skipComment();
				}
			}
			else {
				reader.setLastLineCommentPrefixCharacter(-1);
				loadKeyAndValue(expandLists, document, reader, buffer);
			}
		}

	}
	if (!document.isEmpty() && !documents.contains(document)) {
		documents.add(document);
	}
	return documents;
}

private List<String> tokenize(String json) {
	List<String> list = new ArrayList<>();
	Tracking tracking = new Tracking();
	StringBuilder build = new StringBuilder();
	int index = 0;
	while (index < json.length()) {
		char ch = json.charAt(index);
		if (tracking.in(Tracked.ESCAPE)) {
			build.append(ch);
			index++;
			tracking.set(Tracked.ESCAPE, 0);
			continue;
		}
		switch (ch) {
			case '{' -> tracking.update(Tracked.OBJECT, +1);
			case '}' -> tracking.update(Tracked.OBJECT, -1);
			case '[' -> tracking.update(Tracked.LIST, +1);
			case ']' -> tracking.update(Tracked.LIST, -1);
			case '"' -> tracking.toggle(Tracked.VALUE);
		}
		if (ch == ',' && !tracking.in(Tracked.OBJECT, Tracked.LIST, Tracked.VALUE)) {
			list.add(build.toString());
			build.setLength(0);
		}
		else if (ch == '\\') {
			tracking.set(Tracked.ESCAPE, 1);
		}
		else {
			build.append(ch);
		}
		index++;
	}
	if (!build.isEmpty()) {
		list.add(build.toString().trim());
	}
	return list;
}

private void prepareWebApplicationContext(ServletContext servletContext) {
	Object rootContext = servletContext.getAttribute(WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE);
	if (rootContext != null) {
		if (rootContext == this) {
			throw new IllegalStateException(
					"Cannot initialize context because there is already a root application context present - "
							+ "check whether you have multiple ServletContextInitializers!");
		}
		return;
	}
	try {
		servletContext.setAttribute(WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE, this.context);
		if (logger.isDebugEnabled()) {
			logger.debug("Published root WebApplicationContext as ServletContext attribute with name ["
					+ WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE + "]");
		}
		this.context.setServletContext(servletContext);
		if (logger.isInfoEnabled()) {
			long elapsedTime = System.currentTimeMillis() - this.context.getStartupDate();
			logger.info("Root WebApplicationContext: initialization completed in " + elapsedTime + " ms");
		}
	}
	catch (RuntimeException | Error ex) {
		logger.error("Context initialization failed", ex);
		servletContext.setAttribute(WebApplicationContext.ROOT_WEB_APPLICATION_CONTEXT_ATTRIBUTE, ex);
		throw ex;
	}
}

private static void potentiallyLazifyRepositories(Map<String, RepositoryConfiguration<?>> configurations,
			BeanDefinitionRegistry registry, BootstrapMode mode) {

		if (!(registry instanceof DefaultListableBeanFactory beanFactory) || BootstrapMode.DEFAULT.equals(mode)) {
			return;
		}

		AutowireCandidateResolver resolver = beanFactory.getAutowireCandidateResolver();

		if (!DEFAULT_AUTOWIRE_CANDIDATE_RESOLVERS.contains(resolver.getClass())) {

			logger.warn(LogMessage.format(NON_DEFAULT_AUTOWIRE_CANDIDATE_RESOLVER, resolver.getClass().getName()));
			return;
		}

		AutowireCandidateResolver newResolver = resolver instanceof LazyRepositoryInjectionPointResolver lazy //
				? lazy.withAdditionalConfigurations(configurations) //
				: new LazyRepositoryInjectionPointResolver(configurations);

		beanFactory.setAutowireCandidateResolver(newResolver);

		if (mode.equals(BootstrapMode.DEFERRED)
				&& !beanFactory.containsBean(DeferredRepositoryInitializationListener.class.getName())) {

			logger.debug("Registering deferred repository initialization listener.");
			beanFactory.registerSingleton(DeferredRepositoryInitializationListener.class.getName(),
					new DeferredRepositoryInitializationListener(beanFactory));
		}
	}

@Override
	public <T extends RepositoryConfigurationSource> Collection<RepositoryConfiguration<T>> getRepositoryConfigurations(
			T configSource, ResourceLoader loader, boolean strictMatchesOnly) {

		Assert.notNull(configSource, "ConfigSource must not be null");
		Assert.notNull(loader, "Loader must not be null");

		Set<RepositoryConfiguration<T>> result = new HashSet<>();

		for (BeanDefinition candidate : configSource.getCandidates(loader)) {

			RepositoryConfiguration<T> configuration = getRepositoryConfiguration(candidate, configSource);
			Class<?> repositoryInterface = loadRepositoryInterface(configuration,
					getConfigurationInspectionClassLoader(loader));

			if (repositoryInterface == null) {
				result.add(configuration);
				continue;
			}

			RepositoryMetadata metadata = AbstractRepositoryMetadata.getMetadata(repositoryInterface);

			boolean qualifiedForImplementation = !strictMatchesOnly || configSource.usesExplicitFilters()
					|| isStrictRepositoryCandidate(metadata);

			if (qualifiedForImplementation && useRepositoryConfiguration(metadata)) {
				result.add(configuration);
			}
		}

		return result;
	}

public static void validate(RepositoryComposition composition, Class<?> source,
				RepositoryInformation repositoryInformation) {

			Class<?> repositoryInterface = repositoryInformation.getRepositoryInterface();
			if (repositoryInformation.hasCustomMethod()) {

				if (composition.isEmpty()) {

					throw new IncompleteRepositoryCompositionException(
							String.format("You have custom methods in %s but have not provided a custom implementation",
									org.springframework.util.ClassUtils.getQualifiedName(repositoryInterface)),
							repositoryInterface);
				}

				composition.validateImplementation();
			}

			for (Map.Entry<Class<?>, String> entry : WELL_KNOWN_EXECUTORS.entrySet()) {

				Class<?> executorInterface = entry.getKey();
				if (!executorInterface.isAssignableFrom(repositoryInterface)) {
					continue;
				}

				if (!containsFragmentImplementation(composition, executorInterface)) {
					throw new UnsupportedFragmentException(String.format("Repository %s implements %s but %s does not support %s",
							ClassUtils.getQualifiedName(repositoryInterface), ClassUtils.getQualifiedName(executorInterface),
							ClassUtils.getShortName(source), entry.getValue()), repositoryInterface, executorInterface);
				}
			}
		}

public JpaQueryCreator(PartTree tree, boolean searchQuery, ReturnedType type, ParameterMetadataProvider provider,
			JpqlQueryTemplates templates, JpaEntityMetadata<?> entityMetadata, Metamodel metamodel) {

		super(tree);

		this.searchQuery = searchQuery;
		this.tree = tree;
		this.returnedType = type;
		this.provider = provider;

		JpaParameters bindableParameters = provider.getParameters().getBindableParameters();

		boolean useNamedParameters = false;
		for (JpaParameters.JpaParameter bindableParameter : bindableParameters) {

			if (bindableParameter.isNamedParameter()) {
				useNamedParameters = true;
			}

			if (useNamedParameters && !bindableParameter.isNamedParameter()) {
				useNamedParameters = false;
				break;
			}
		}

		this.useNamedParameters = useNamedParameters;
		this.templates = templates;
		this.escape = provider.getEscape();
		this.entityType = metamodel.entity(type.getDomainType());
		this.entity = JpqlQueryBuilder.entity(entityMetadata);
		this.metamodel = metamodel;
		this.similarityNormalizer = provider.getSimilarityNormalizer();
	}

@Override
		public @Nullable Object invoke(MethodInvocation invocation) throws Throwable {

			Method method = invocation.getMethod();

			if (!implementations.contains(method)) {
				return invocation.proceed();
			}

			MethodInvocation oldInvocation = currentInvocation.get();
			currentInvocation.set(invocation);

			try {

				CrudMethodMetadata metadata = (CrudMethodMetadata) TransactionSynchronizationManager.getResource(method);

				if (metadata != null) {
					return invocation.proceed();
				}

				CrudMethodMetadata methodMetadata = metadataCache.get(method);

				if (methodMetadata == null) {

					methodMetadata = new DefaultCrudMethodMetadata(method);
					CrudMethodMetadata tmp = metadataCache.putIfAbsent(method, methodMetadata);

					if (tmp != null) {
						methodMetadata = tmp;
					}
				}

				TransactionSynchronizationManager.bindResource(method, methodMetadata);

				try {
					return invocation.proceed();
				} finally {
					TransactionSynchronizationManager.unbindResource(method);
				}
			} finally {
				currentInvocation.set(oldInvocation);
			}
		}

public void begin_class(int version, final int access, String className, final Type superType, final Type[] interfaces, String source) {
    final Type classType = Type.getType("L" + className.replace('.', '/') + ";");
    classInfo = new ClassInfo() {
        @Override
public Type getType() {
            return classType;
        }
        @Override
public Type getSuperType() {
            return (superType != null) ? superType : Constants.TYPE_OBJECT;
        }
        @Override
public Type[] getInterfaces() {
            return interfaces;
        }
        @Override
public int getModifiers() {
            return access;
        }
    };
    cv.visit(version,
             access,
             classInfo.getType().getInternalName(),
             null,
             classInfo.getSuperType().getInternalName(),
             TypeUtils.toInternalNames(interfaces));
    if (source != null) {
cv.visitSource(source, null);
}
    init();
}

public byte[] toByteArray() {

byte[] b = ((ClassWriter) DebuggingClassWriter.super.cv).toByteArray();
if (debugLocation != null) {
	String dirs = className.replace('.', File.separatorChar);
	try {
		new File(debugLocation + File.separatorChar + dirs).getParentFile().mkdirs();

		File file = new File(new File(debugLocation), dirs + ".class");
		OutputStream out = new BufferedOutputStream(new FileOutputStream(file));
		try {
			out.write(b);
		} finally {
			out.close();
		}

		if (traceCtor != null) {
			file = new File(new File(debugLocation), dirs + ".asm");
			out = new BufferedOutputStream(new FileOutputStream(file));
			try {
				ClassReader cr = new ClassReader(b);
				PrintWriter pw = new PrintWriter(new OutputStreamWriter(out));
				ClassVisitor tcv = (ClassVisitor)traceCtor.newInstance(new Object[]{null, pw});
				cr.accept(tcv, 0);
				pw.flush();
			} finally {
				out.close();
			}
		}
	} catch (Exception e) {
		throw new CodeGenerationException(e);
	}
}
return b;
}

public static void wrap_undeclared_throwable(CodeEmitter e, Block handler, Type[] exceptions, Type wrapper) {
    Set set = (exceptions == null) ? Collections.EMPTY_SET : new HashSet(Arrays.asList(exceptions));

    if (set.contains(Constants.TYPE_THROWABLE)) {
return;
}

    boolean needThrow = exceptions != null;
    if (!set.contains(Constants.TYPE_RUNTIME_EXCEPTION)) {
        e.catch_exception(handler, Constants.TYPE_RUNTIME_EXCEPTION);
        needThrow = true;
    }
    if (!set.contains(Constants.TYPE_ERROR)) {
        e.catch_exception(handler, Constants.TYPE_ERROR);
        needThrow = true;
    }
    if (exceptions != null) {
        for (Type exception : exceptions) {
            e.catch_exception(handler, exception);
        }
    }
    if (needThrow) {
        e.athrow();
    }
    // e -> eo -> oeo -> ooe -> o
    e.catch_exception(handler, Constants.TYPE_THROWABLE);
    e.new_instance(wrapper);
    e.dup_x1();
    e.swap();
    e.invoke_constructor(wrapper, CSTRUCT_THROWABLE);
    e.athrow();
}

protected V createEntry(final K key, KK cacheKey, Object v) {
    FutureTask<V> task;
    boolean creator = false;
    if (v != null) {
        // Another thread is already loading an instance
        task = (FutureTask<V>) v;
    } else {
        task = new FutureTask<>(() -> loader.apply(key));
        Object prevTask = map.putIfAbsent(cacheKey, task);
        if (prevTask == null) {
            // creator does the load
            creator = true;
            task.run();
        } else if (prevTask instanceof FutureTask) {
            task = (FutureTask<V>) prevTask;
        } else {
            return (V) prevTask;
        }
    }

    V result;
    try {
        result = task.get();
    } catch (InterruptedException e) {
        throw new IllegalStateException("Interrupted while loading cache item", e);
    } catch (ExecutionException e) {
        Throwable cause = e.getCause();
        if (cause instanceof RuntimeException runtimeException) {
            throw runtimeException;
        }
        throw new IllegalStateException("Unable to load cache item", cause);
    }
    if (creator) {
        map.put(cacheKey, result);
    }
    return result;
}
